SELECT name, scientific_name, link
FROM tree_species
WHERE conservation_status = 'Critically Endangered';

SELECT COUNT(*)
FROM tree_species
WHERE soil_preference = 'Loam';

SELECT DISTINCT u.user_name, u.role
FROM access_logs al
JOIN users u ON al.user_id = u.user_id;

SELECT name, scientific_name, abundance, profits, conservation_status
FROM tree_species
WHERE abundance > (SELECT AVG(abundance) FROM tree_species);

SELECT name, scientific_name 
FROM tree_species 
ORDER BY name ASC;

SELECT AVG(profits) AS average_profits
FROM tree_species
WHERE species_id > 500;

SELECT tree_species.name, users.user_name
FROM tree_species
JOIN users ON tree_species.created_by = users.user_id;
